function makeStateMachine(entity, states, initial) {
  const sm = { entity, states, name: null };
  sm.set = (name) => {
    if (sm.name === name) return;
    sm.name = name; entity.stateTime = 0;
    const st = states[name];
    if (st && st.enter) st.enter(entity);
  };
  sm.update = (dt) => {
    entity.stateTime += dt;
    const st = states[sm.name];
    if (st && st.update) st.update(entity, dt);
  };
  sm.set(initial);
