// Deterministic RNG + generated grid. NEVER inline a huge literal 2D
// array (local models loop on it) — generate it from a seed instead.
function mulberry32(seed) {
  let a = seed >>> 0;
  return function () {
    a |= 0; a = (a + 0x6D2B79F5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
function buildGrid(w, h, seed) {
  const rng = mulberry32(seed);
  const g = [];
  for (let y = 0; y < h; y++) {
    const row = [];
    for (let x = 0; x < w; x++) {
      const border = (x === 0 || y === 0 || x === w - 1 || y === h - 1);
      row.push(border || rng() < 0.18 ? 1 : 0); // 1 = wall, 0 = floor
    }
    g.push(row);
  }
  return g;
}

