// Grid BFS (4-neighbour). Returns [[x,y],...] start->goal, or null.
// grid[y][x] truthy = wall. Use for chasing enemies / creep routing.
function bfsPath(grid, sx, sy, gx, gy) {
  const H = grid.length, W = grid[0].length;
  const key = (x, y) => y * W + x;
  const prev = new Map();
  const q = [[sx, sy]]; prev.set(key(sx, sy), null);
  while (q.length) {
    const [x, y] = q.shift();
    if (x === gx && y === gy) {
      const path = []; let k = key(x, y);
      while (k !== null) { const px = k % W, py = (k - px) / W; path.push([px, py]); k = prev.get(k); }
      return path.reverse();
    }
    for (const [dx, dy] of [[1,0],[-1,0],[0,1],[0,-1]]) {
      const nx = x + dx, ny = y + dy;
      if (nx < 0 || ny < 0 || nx >= W || ny >= H) continue;
      if (grid[ny][nx] || prev.has(key(nx, ny))) continue;
      prev.set(key(nx, ny), key(x, y)); q.push([nx, ny]);
    }
  }
  return null;
}

