// First-person look + move. Expose on state so probes can read it.
state.player = state.player || { x: 0, y: 0, z: 0, yaw: 0, pitch: 0 };
const SENS = 0.0025, SPEED = 4; // rad/px, units/sec
canvas.addEventListener('click', () => canvas.requestPointerLock());
addEventListener('mousemove', e => {
  if (document.pointerLockElement !== canvas) return;
  state.player.yaw += e.movementX * SENS;
  state.player.pitch -= e.movementY * SENS;
  const lim = Math.PI/2 - 0.01;
  state.player.pitch = Math.max(-lim, Math.min(lim, state.player.pitch));
});
// In update(dt): move relative to yaw.
function moveFP(dt) {
  const p = state.player, s = SPEED * dt;
  const fx = Math.sin(p.yaw), fz = Math.cos(p.yaw);
  if (Input.down('KeyW')) { p.x += fx*s; p.z += fz*s; }
  if (Input.down('KeyS')) { p.x -= fx*s; p.z -= fz*s; }
  if (Input.down('KeyD')) { p.x += fz*s; p.z -= fx*s; }
  if (Input.down('KeyA')) { p.x -= fz*s; p.z += fx*s; }
}

// camera tracks player, clamped to [0, worldW-viewW].
const cam = { x: 0, y: 0 };
function updateCamera(viewW, viewH, worldW, worldH) {
  cam.x = Math.max(0, Math.min(state.player.x - viewW/2, worldW - viewW));
  cam.y = Math.max(0, Math.min(state.player.y - viewH/2, worldH - viewH));
}
// In draw(): translate once, draw world in WORLD coords, then reset.
function drawWorld(ctx, viewW, viewH, worldW, worldH) {
  updateCamera(viewW, viewH, worldW, worldH);
  ctx.save();
  ctx.translate(-Math.round(cam.x), -Math.round(cam.y)); // round to avoid jitter
  // ... draw tiles/entities at their world x,y ...
  ctx.restore();
  // HUD draws AFTER restore in screen space.
}

// Call after moving each entity. W,H are the play-field size.
function wrap(e, W, H) {
  if (e.x < 0) e.x += W; else if (e.x >= W) e.x -= W;
  if (e.y < 0) e.y += H; else if (e.y >= H) e.y -= H;
}
// For objects with radius, wrap by their full extent so they slide off
// smoothly instead of popping:
function wrapR(e, W, H, r) {
  if (e.x < -r) e.x = W + r; else if (e.x > W + r) e.x = -r;
  if (e.y < -r) e.y = H + r; else if (e.y > H + r) e.y = -r;
}

// Build once per entity (store verts), draw every frame.
function makePolygon(radius, points = 11, jitter = 0.4) {
  const verts = [];
  for (let i = 0; i < points; i++) {
    const a = (i / points) * Math.PI * 2;
    const r = radius * (1 - jitter/2 + Math.random() * jitter);
    verts.push({ x: Math.cos(a) * r, y: Math.sin(a) * r });
  }
  return verts; // irregular outline, never a circle
}
function drawPolygon(ctx, e) {
  ctx.save(); ctx.translate(e.x, e.y); ctx.rotate(e.rot || 0);
  ctx.beginPath();
  e.verts.forEach((v, i) => i ? ctx.lineTo(v.x, v.y) : ctx.moveTo(v.x, v.y));
  ctx.closePath(); ctx.stroke();
  ctx.restore();
}

function buildHash(entities, cell) {
  const grid = new Map();
  const key = (cx, cy) => cx + ',' + cy;
  for (const e of entities) {
    const cx = Math.floor(e.x / cell), cy = Math.floor(e.y / cell);
    const k = key(cx, cy);
    (grid.get(k) || grid.set(k, []).get(k)).push(e);
  }
  return { grid, cell, key };
}
// Candidates near entity e (3x3 neighborhood):
function near(h, e) {
  const cx = Math.floor(e.x / h.cell), cy = Math.floor(e.y / h.cell), out = [];
  for (let dx=-1; dx<=1; dx++) for (let dy=-1; dy<=1; dy++) {
    const c = h.grid.get(h.key(cx+dx, cy+dy)); if (c) out.push(...c);
  }
  return out;
}
